INSERT INTO public.templates (id, name, description, industry, icon, color_theme, parameters, returns, formulas, outputs, scenarios, is_builtin, sort_order) VALUES ('3cba0c38-407c-417b-ace8-8c712f6ac9d1', 'SaaS / Software', 'Per-seat subscription with productivity gains', 'saas', 'cloud', 'orange', '[{"key": "seats", "max": 5000, "min": 5, "help": "Total active platform seats", "step": 5, "type": "slider", "unit": "users", "label": "Number of Seats", "default": 250}, {"key": "price_per_seat", "max": 2000, "min": 10, "help": "Annual price per seat", "step": 10, "type": "currency", "label": "Price per Seat", "default": 120}, {"key": "implementation_cost", "max": 500000, "min": 0, "help": "One-time onboarding/setup", "step": 1000, "type": "currency", "label": "Implementation Cost", "default": 25000}]'::jsonb, '[{"key": "hours_saved_per_user", "max": 20, "min": 0, "help": "Productivity reclaimed weekly", "step": 0.5, "type": "slider", "unit": "hrs", "label": "Hours Saved / User / Week", "default": 4}, {"key": "loaded_hourly_rate", "max": 300, "min": 20, "help": "Fully-loaded cost per hour", "step": 5, "type": "currency", "label": "Loaded Hourly Rate", "default": 75}, {"key": "churn_reduction", "max": 50, "min": 0, "help": "Estimated retention lift", "step": 1, "type": "percent", "label": "Churn Reduction", "default": 8}]'::jsonb, '[{"key": "annual_cost", "label": "Annual Investment", "expression": "seats * price_per_seat + implementation_cost"}, {"key": "productivity_savings", "label": "Productivity Savings", "expression": "seats * hours_saved_per_user * 50 * loaded_hourly_rate"}, {"key": "churn_savings", "label": "Retention Value", "expression": "seats * price_per_seat * (churn_reduction / 100)"}, {"key": "annual_gain", "label": "Annual Gain", "expression": "productivity_savings + churn_savings"}]'::jsonb, '[]'::jsonb, '{"expected": 1, "optimistic": 1.25, "conservative": 0.75}'::jsonb, true, 1) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.templates (id, name, description, industry, icon, color_theme, parameters, returns, formulas, outputs, scenarios, is_builtin, sort_order) VALUES ('3b61b349-70f5-4c03-8a5b-30c80dc551ae', 'Professional Services', 'Billable hours, utilization & margin uplift', 'services', 'briefcase', 'orange', '[{"key": "billable_consultants", "max": 500, "min": 1, "help": "Headcount on billable work", "step": 1, "type": "slider", "unit": "FTE", "label": "Billable Consultants", "default": 25}, {"key": "engagement_cost", "max": 1000000, "min": 0, "help": "Annual platform cost", "step": 1000, "type": "currency", "label": "Tooling Investment", "default": 80000}, {"key": "current_utilization", "max": 95, "min": 20, "help": "Today''s billable utilization", "step": 1, "type": "percent", "label": "Current Utilization", "default": 62}]'::jsonb, '[{"key": "utilization_lift", "max": 30, "min": 0, "help": "Points of utilization gained", "step": 0.5, "type": "percent", "label": "Utilization Lift", "default": 7}, {"key": "avg_bill_rate", "max": 1000, "min": 50, "help": "Per billable hour", "step": 10, "type": "currency", "label": "Avg Bill Rate", "default": 175}, {"key": "hours_per_year", "max": 2200, "min": 1500, "help": "Available billable hours", "step": 10, "type": "number", "label": "Working Hours / FTE", "default": 1800}]'::jsonb, '[{"key": "annual_cost", "label": "Annual Investment", "expression": "engagement_cost"}, {"key": "recovered_hours", "label": "Recovered Billable Hours", "expression": "billable_consultants * hours_per_year * (utilization_lift / 100)"}, {"key": "annual_gain", "label": "Annual Gain", "expression": "recovered_hours * avg_bill_rate"}]'::jsonb, '[]'::jsonb, '{"expected": 1, "optimistic": 1.25, "conservative": 0.75}'::jsonb, true, 2) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.templates (id, name, description, industry, icon, color_theme, parameters, returns, formulas, outputs, scenarios, is_builtin, sort_order) VALUES ('362f59ba-cc72-482c-8b61-c5a8d1962819', 'AI / Automation', 'Workflow automation with FTE equivalent savings', 'ai', 'sparkles', 'orange', '[{"key": "platform_cost", "max": 1000000, "min": 0, "help": "Annual subscription", "step": 1000, "type": "currency", "label": "Platform / License Cost", "default": 60000}, {"key": "implementation_cost", "max": 500000, "min": 0, "help": "Setup & integration", "step": 1000, "type": "currency", "label": "Implementation", "default": 40000}, {"key": "workflows", "max": 200, "min": 1, "help": "Distinct processes automated", "step": 1, "type": "slider", "unit": "flows", "label": "Workflows Automated", "default": 12}]'::jsonb, '[{"key": "hours_per_workflow", "max": 80, "min": 1, "help": "Manual hours eliminated per workflow", "step": 1, "type": "slider", "unit": "hrs", "label": "Hours Saved / Workflow / Week", "default": 12}, {"key": "loaded_hourly_rate", "max": 300, "min": 20, "help": "Cost of human labor avoided", "step": 5, "type": "currency", "label": "Loaded Hourly Rate", "default": 85}, {"key": "error_reduction_value", "max": 2000000, "min": 0, "help": "Annual cost of errors eliminated", "step": 1000, "type": "currency", "label": "Error / Rework Cost Avoided", "default": 75000}]'::jsonb, '[{"key": "annual_cost", "label": "Annual Investment", "expression": "platform_cost + implementation_cost"}, {"key": "hours_automated", "label": "Hours Automated / Year", "expression": "workflows * hours_per_workflow * 50"}, {"key": "fte_equivalent", "label": "FTE Equivalent", "expression": "workflows * hours_per_workflow * 50 / 1800"}, {"key": "labor_savings", "label": "Labor Savings", "expression": "workflows * hours_per_workflow * 50 * loaded_hourly_rate"}, {"key": "annual_gain", "label": "Annual Gain", "expression": "labor_savings + error_reduction_value"}]'::jsonb, '[]'::jsonb, '{"expected": 1, "optimistic": 1.25, "conservative": 0.75}'::jsonb, true, 3) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.templates (id, name, description, industry, icon, color_theme, parameters, returns, formulas, outputs, scenarios, is_builtin, sort_order) VALUES ('fedaa664-d6f1-4c03-b045-db426f93fdcc', 'Blank / Custom', 'Start from scratch — add your own parameters', 'custom', 'plus-square', 'orange', '[{"key": "investment", "max": 1000000, "min": 0, "help": "Upfront cost", "step": 1000, "type": "currency", "label": "Initial Investment", "default": 50000}]'::jsonb, '[{"key": "annual_savings", "max": 5000000, "min": 0, "help": "Direct savings per year", "step": 1000, "type": "currency", "label": "Annual Savings", "default": 150000}]'::jsonb, '[{"key": "annual_cost", "label": "Annual Investment", "expression": "investment"}, {"key": "annual_gain", "label": "Annual Gain", "expression": "annual_savings"}]'::jsonb, '[]'::jsonb, '{"expected": 1, "optimistic": 1.25, "conservative": 0.75}'::jsonb, true, 99) ON CONFLICT (id) DO NOTHING;